import { describe, expect, it } from '@a0n/gnosis/test';
import {
  GnosisTauriEdgeExecutionSurface,
  buildTauriEdgeReactorPolicy,
  type ExecuteWasmArtifactRequest,
  type TauriEdgeArtifactManifest,
  type WasmExecutionResponse,
} from './index';

const WASM_DOUBLE_FIXTURE_BASE64 =
  '';

function createManifest(
  overrides: Partial<TauriEdgeArtifactManifest> = {}
): TauriEdgeArtifactManifest {
  return {
    version: 1,
    runtimeTarget: 'tauri-edge',
    artifactId: 'tauri-edge-demo',
    application: {
      name: 'demo',
      version: '0.1.0',
      configPath: 'src-tauri/tauri.conf.json',
    },
    bundleDigest: 'bundle-digest',
    manifestDigest: 'manifest-digest',
    capabilityDigest: 'capability-digest',
    ucanAudience: 'aeon://tauri-edge/demo',
    ucanRequiredCaps: ['tauri-edge/invoke aeon://artifact/tauri-edge-demo'],
    runtimeBindingHash: 'binding-demo-1',
    snapshotCompatibility: 'reconstructable-v1',
    entrypoints: {
      guestWasm: 'guest.wasm',
      commandSurface: 'commands.json',
      capabilityManifest: 'capabilities.json',
    },
    capabilityPolicy: [
      { key: 'invoke', disposition: 'supported' },
      { key: 'events', disposition: 'supported' },
      { key: 'http', disposition: 'supported' },
      { key: 'storage', disposition: 'supported' },
      { key: 'fs', disposition: 'supported' },
      { key: 'shell', disposition: 'delegated' },
      { key: 'updater', disposition: 'denied' },
      { key: 'tray', disposition: 'denied' },
      { key: 'global-shortcut', disposition: 'denied' },
      { key: 'process', disposition: 'denied' },
      { key: 'plugin', disposition: 'delegated' },
    ],
    zkPolicy: {
      mode: 'required',
      protectedPaths: ['/sessions/private'],
      proofSystem: 'mock-zk',
    },
    fragments: [],
    createdAt: '2026-03-26T12:00:00.000Z',
    ...overrides,
  };
}

function createStubWasmSurface(): {
  readonly registerCalls: ExecuteWasmArtifactRequest[];
  readonly executeCalls: ExecuteWasmArtifactRequest[];
  readonly surface: GnosisTauriEdgeExecutionSurface;
} {
  const registerCalls: ExecuteWasmArtifactRequest[] = [];
  const executeCalls: ExecuteWasmArtifactRequest[] = [];
  const wasmSurface = {
    register(request: ExecuteWasmArtifactRequest): { artifactId: string } {
      registerCalls.push(request);
      return {
        artifactId: String(request.artifactId ?? 'registered-artifact'),
      };
    },
    async execute(
      request: ExecuteWasmArtifactRequest
    ): Promise<WasmExecutionResponse> {
      executeCalls.push(request);
      return {
        artifactId: String(request.artifactId ?? 'registered-artifact'),
        exportName: 'double_value',
        abi: 'scalar-v1',
        payload: 42,
        logs: '',
        executionAuth: {
          enforced: request.executionAuth?.enforce === true,
          principal: request.executionAuth?.principal ?? null,
          capabilityCount: request.executionAuth?.capabilities.length ?? 0,
          reactorHandleGrantCount:
            request.executionAuth?.reactorHandleGrants?.length ?? 0,
          reactorHandleKinds: [],
          source: request.executionAuth ? 'explicit' : 'none',
        },
      };
    },
  };

  return {
    registerCalls,
    executeCalls,
    surface: new GnosisTauriEdgeExecutionSurface({
      wasmSurface: wasmSurface as never,
    }),
  };
}

describe('tauri-edge runtime admission', () => {
  it('builds a reactor policy for invoke, stream, and vfs surfaces', () => {
    const policy = buildTauriEdgeReactorPolicy({
      manifest: createManifest(),
    });

    expect(policy.version).toBe('aeon_reactor_v1');
    expect(policy.runtime).toBe('tauri-edge');
    expect(policy.rules.some((rule) => rule.operation === 'request.read')).toBe(
      true
    );
    expect(policy.rules.some((rule) => rule.operation === 'stream.open')).toBe(
      true
    );
    expect(policy.rules.some((rule) => rule.operation === 'vfs.read')).toBe(
      true
    );
  });

  it('executes an admitted tauri-edge command through the wasm lane', async () => {
    const { executeCalls, registerCalls, surface } = createStubWasmSurface();
    const result = await surface.invoke({
      manifest: createManifest(),
      guestWasmBase64: WASM_DOUBLE_FIXTURE_BASE64,
      command: 'double',
      input: 21,
      commandSurface: {
        commands: {
          double: {
            exportName: 'double_value',
            abi: 'scalar-v1',
          },
        },
      },
      executionAuth: {
        enforce: true,
        principal: 'did:key:runtime-user',
        capabilities: [
          {
            can: 'tauri-edge/invoke',
            with: 'aeon://artifact/tauri-edge-demo',
          },
        ],
      },
    });

    expect(result.status).toBe('executed');
    expect(result.payload).toBe(42);
    expect(result.abi).toBe('scalar-v1');
    expect(result.executionAuth?.principal).toBe('did:key:runtime-user');
    expect(registerCalls[0]?.artifactId).toBe('tauri-edge-demo:double_value');
    expect(registerCalls[0]?.wasmBase64).toBe(WASM_DOUBLE_FIXTURE_BASE64);
    expect(executeCalls[0]?.artifactId).toBe('tauri-edge-demo:double_value');
    expect(executeCalls[0]?.input).toBe(21);
  });

  it('rejects invoke when the UCAN scope is missing', async () => {
    const { surface } = createStubWasmSurface();
    await expect(
      surface.invoke({
        manifest: createManifest(),
        guestWasmBase64: WASM_DOUBLE_FIXTURE_BASE64,
        command: 'double',
        input: 9,
        commandSurface: {
          commands: {
            double: {
              exportName: 'double_value',
              abi: 'scalar-v1',
            },
          },
        },
        executionAuth: {
          enforce: true,
          principal: 'did:key:runtime-user',
          capabilities: [],
        },
      })
    ).rejects.toThrow('Missing capability tauri-edge/invoke');
  });

  it('rejects runtime binding mismatches and missing zk proofs on protected paths', async () => {
    const { surface } = createStubWasmSurface();
    await expect(
      surface.invoke({
        manifest: createManifest(),
        guestWasmBase64: WASM_DOUBLE_FIXTURE_BASE64,
        command: 'double',
        input: 9,
        commandSurface: {
          commands: {
            double: {
              exportName: 'double_value',
              abi: 'scalar-v1',
            },
          },
        },
        executionAuth: {
          enforce: true,
          capabilities: [
            {
              can: 'tauri-edge/invoke',
              with: 'aeon://artifact/tauri-edge-demo',
            },
          ],
        },
        runtimeBindingHash: 'binding-other',
      })
    ).rejects.toThrow('runtime binding mismatch');

    await expect(
      surface.invoke({
        manifest: createManifest(),
        guestWasmBase64: WASM_DOUBLE_FIXTURE_BASE64,
        command: 'double',
        input: 9,
        commandSurface: {
          commands: {
            double: {
              exportName: 'double_value',
              abi: 'scalar-v1',
            },
          },
        },
        executionAuth: {
          enforce: true,
          capabilities: [
            {
              can: 'tauri-edge/invoke',
              with: 'aeon://artifact/tauri-edge-demo',
            },
          ],
        },
        scopePath: '/sessions/private/demo',
        runtimeBindingHash: 'binding-demo-1',
      })
    ).rejects.toThrow('requires a ZK proof');
  });
});
